INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'clubs', 'CLUBS: cricket, volleyball, football, badminton, basketball, lawn tennis, kabaddi, chess, carrom, gym, athletics, table tennis, Business management, Aavartan (Dance), Saaz (Music), Jazbaat (Dramatics), Abhivyakti (Arts & Craft), Aakriti (Film & Photography), and Samvaad (Literary),Robotics (ERS) and Aero Fabrication, CAD & 3D Printing Club, BitByte TPC, Racing.', 'Clubs at IIITDM Jabalpur — Sports: Cricket, Volleyball, Football, Badminton, Basketball, Lawn Tennis, Kabaddi, Chess, Carrom, Gym, Athletics, Table Tennis. Cultural: Aavartan (Dance), Saaz (Music), Jazbaat (Dramatics), Abhivyakti (Arts & Craft), Aakriti (Film & Photography), Samvaad (Literary). Technical: Robotics (ERS), Aero Fabrication, CAD & 3D Printing Club, BitByte TPC, Racing. Other: Business Management.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'attendance', 'ATTENDANCE:75%(Mandatory)', 'At IIITDM Jabalpur, 75% attendance is mandatory.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'wifi', 'WIFI:LAN', 'IIITDM Jabalpur has LAN available in hostels.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'fests', 'FESTS: Abhikalpan, Tarang, Riwayat', 'IIITDM Jabalpur hosts three main fests: Abhikalpan, Tarang, and Riwayat.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'hostels', 'HOSTELS: Vasishtha Hostel (HALL-I)[4th year boys], Aryabhatta Hostel (HALL-III)[2nd year boys], Vivekananda Hostel (HALL-IV)[3rd year boys], Nagarjuna Hostel [2nd and 3rd year girls], Panini Hostel [1st year boys], Maa Saraswati Girls Hostel[1st years 4th years PhD girls]', 'IIITDM Jabalpur has six hostels. Boys: Vasishtha Hostel (Hall-I, 4th year), Aryabhatta Hostel (Hall-III, 2nd year), Vivekananda Hostel (Hall-IV, 3rd year), Panini Hostel (1st year). Girls: Nagarjuna Hostel (2nd and 3rd year), Maa Saraswati Girls Hostel (1st year, 4th year, and PhD).', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'mess', 'MESS: Central mess 1:Vegetarian, Central mess 2:Non vegetarian', 'IIITDM Jabalpur has two central messes: Central Mess 1 (Vegetarian) and Central Mess 2 (Non-vegetarian).', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'laundry', 'LAUNDRY: each hostel is equipped with its own laundry facilities.', 'Each hostel at IIITDM Jabalpur is equipped with its own laundry facilities.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'elections', 'ELECTIONS: Student Affairs conducts elections, and those elections are hosted/organized by Senate members.', 'At IIITDM Jabalpur, Student Affairs conducts elections, which are hosted and organized by Senate members.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'sports', 'SPORTS: Only students who are involved in clubs can play sports on campus; others are not allowed.', 'At IIITDM Jabalpur, only students who are involved in sports clubs can play sports on campus. Others are not allowed to use the sports facilities.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'canteen', 'CANTEENS: Aryabhatta Hostel, Vasishtha Hostel, Vivekananda Hostel, Maa Saraswati', 'IIITDM Jabalpur has canteens in four hostels: Aryabhatta Hostel, Vasishtha Hostel, Vivekananda Hostel, and Maa Saraswati Hostel.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'shops', 'SHOPS: Nescafe, vegetable and fruits shop, general store', 'Shops on the IIITDM Jabalpur campus: Nescafe, a Vegetable and Fruits Shop, and a General Store.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'fines', 'FINES: Every hostel maintains an attendance sheet. If a student is absent, a fine of Rs 50 is mandatory. This rule applies to all year batches.', 'At IIITDM Jabalpur, every hostel maintains an attendance sheet. If a student is found absent, a fine of Rs 50 is imposed. This rule applies to all year batches.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'gym', 'GYM: BOYS 1st year:5:30am-7:30am, 2nd year:11am-1pm,8:30pm-10pm, 3rd year:6:30pm-8:30pm, Final Year:6:30pm-8:30pm, Masters and Phd:11am-1pm,8:30pm-10pm. GIRLS 1st year:7:30-9:30am, 2nd year:7:30-9:30am, 3rd year:4:00pm-6:30pm, Final Year:4:00pm-6:30pm, Masters and Phd:4:00pm-6:30pm', 'IIITDM Jabalpur gym timings — Boys: 1st year 5:30-7:30 AM, 2nd year 11 AM-1 PM and 8:30-10 PM, 3rd year 6:30-8:30 PM, 4th year 6:30-8:30 PM, Masters/PhD 11 AM-1 PM and 8:30-10 PM. Girls: 1st year 7:30-9:30 AM, 2nd year 7:30-9:30 AM, 3rd year 4:00-6:30 PM, 4th year 4:00-6:30 PM, Masters/PhD 4:00-6:30 PM.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'medical', 'MEDICAL: Primary Health Centre', 'IIITDM Jabalpur has a Primary Health Centre on campus for medical needs.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'transport', 'Transport:dumna airport to college:5km,jabalpur railway station to college:10km.', 'Dumna Airport is 5 km from IIITDM Jabalpur campus. Jabalpur Railway Station is 10 km from campus.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'restaurants', 'Restarurants: chamrminar biryani point, barbeque, handi.', 'Nearby restaurants around IIITDM Jabalpur: Charminar Biryani Point, Barbeque, and Handi.', 1, '04/04/26', '04/04/26', 'text_file');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIITDM Jabalpur', 'ambassador_text_file', 'tourist_malls', 'tourist: Dumna Nature Reserve. Malls: Samdareeya, PVRmall', 'Tourist spots near IIITDM Jabalpur: Dumna Nature Reserve. Nearby malls: Samdareeya Mall and PVR Mall.', 1, '04/04/26', '04/04/26', 'text_file');
